        return button
    }()

    private let legacyButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Fetch from Legacy (Insecure)", for: .normal)
        button.backgroundColor = .systemRed
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        return button
    }()

    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        apiButton.addTarget(self, action: #selector(fetchFromAPI), for: .touchUpInside)
        legacyButton.addTarget(self, action: #selector(fetchFromLegacy), for: .touchUpInside)
    }

    private func setupUI() {
        view.backgroundColor = .white

        let stackView = UIStackView(arrangedSubviews: [statusLabel, apiButton, legacyButton])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.distribution = .fillEqually
        stackView.translatesAutoresizingMaskIntoConstraints = false

        view.addSubview(stackView)

        NSLayoutConstraint.activate([
            stackView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 40),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -40),
            statusLabel.heightAnchor.constraint(equalToConstant: 100)
        ])
    }

    @objc private func fetchFromAPI() {
        makeRequest(url: apiURL, description: "API (Secure)")
    }

    @objc private func fetchFromLegacy() {
        makeRequest(url: legacyURL, description: "Legacy (Insecure)")
    }

    private func makeRequest(url: URL, description: String) {
        DispatchQueue.main.async {
            self.statusLabel.text = "Fetching from \(description)..."
        }

        let task = URLSession.shared.dataTask(with: url) { [weak self] data, response, error in
            DispatchQueue.main.async {
                if let error = error {
                    self?.statusLabel.text = "Error from \(description): \(error.localizedDescription)"
                    print("Error fetching from \(description): \(error)")
                    return
                }

                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.statusLabel.text = "Invalid response from \(description)"
                    print("Invalid response from \(description)")
                    return
                }

                if (200...299).contains(httpResponse.statusCode) {
                    let dataString = data.flatMap { String(data: $0, encoding: .utf8) } ?? "No data"
                    self?.statusLabel.text = "Success from \(description) (Status: \(httpResponse.statusCode))\nData: \(dataString.prefix(100))..."
                    print("Success from \(description) (Status: \(httpResponse.statusCode))\nData: \(dataString)")
                } else {
                    self?.statusLabel.text = "Failed from \(description) (Status: \(httpResponse.statusCode))"
                    print("Failed from \(description) (Status: \(httpResponse.statusCode))")
                }
            }
        }
        task.resume()
    }
